SELECT company_name
FROM companies
WHERE company_id IN (
    SELECT company_id
    FROM launches
);

SELECT payload_name, COUNT(*) AS payload_count
FROM payloads
GROUP BY payload_name;

SELECT COUNT(l.launch_id) AS number_of_launches
FROM launches l
WHERE l.company_id = (SELECT company_id FROM companies WHERE company_name = 'SpaceX');

SELECT launch_date
FROM launches
WHERE company_id = (SELECT company_id FROM companies WHERE company_name = 'NASA');
